export const qoActivities: Activity[] = [
  {"id":"qo-ant-trail-watch","title":"Ant Trail Detective Watch","altNames":["Ant Highway Watching","Insect Trail Observation","Bug Detective Sit"],"type":"Quiet","place":"Outside","ageMin":6,"ageMax":12,"durationMin":30,"groupMin":null,"groupMax":null,"energy":1,"prep":"Low","blurb":"Crouch low over a busy patch of ground and quietly trace where the ants are going, what they carry, and how they pass messages.","materials":["Paper, one sheet per camper","Crayons, assorted","Magnifiers, one per pair (optional)","Sidewalk chalk, a few sticks"],"materialTags":["Paper","Crayons","Sidewalk chalk"],"steps":["Walk the group to a shady, hard-surface or bare-soil spot where ants are already active and have each camper settle on the ground a body-length apart.","Ask everyone to find ONE ant and follow it silently with their eyes for two full minutes without touching it.","Have campers draw the ant's path on paper as a winding line, marking where it stopped, turned, or met another ant.","Use chalk to lightly outline the real trail on the ground so the whole group can see the 'ant highway' from above.","Gather in and let two or three campers whisper one thing their ant did that surprised them.","Erase or let the chalk fade and remind the group the ants keep working after we leave."],"notes":"Pair shy or wiggly kids with a magnifier to give restless hands a job; if ants are scarce, switch the target to any single small bug. The activity stalls if kids are too far from real insect activity, so scout the spot first.","safety":"Choose a spot clear of ant species that bite or sting and tell campers to observe with eyes only, never touch or block the trail.","ages":["g13","g46"],"rating":0,"media":[{"title":"Following an Ant Trail","url":"https://www.youtube.com/watch?v=epV_JlqNXf0"}],"links":[{"label":"How-to & more ideas","url":"https://getthekidsoutside.com/sit-spot-activities/"}],"variations":["Time how many seconds an ant takes to cross one chalk circle and compare across the group.","Give each camper a 'mission card' to find an ant carrying food, an ant going home, and two ants meeting."],"subsets":[["Spread campers out so nobody is leaning over the same square of ground."],[],["Show that a dotted line can mean 'I lost my ant here' so kids don't feel they failed."],["Keep chalk lines thin so you are not redrawing the trail the ants follow by scent."],[],[]]},
  {"id":"qo-color-match-hunt","title":"Nature Color-Match Quest","altNames":["Paint Chip Nature Hunt","Color Matching Walk","Shades of Outdoors"],"type":"Quiet","place":"Outside","ageMin":7,"ageMax":13,"durationMin":30,"groupMin":null,"groupMax":null,"energy":1,"prep":"Medium","blurb":"Armed with a homemade strip of colored squares, campers move slowly to find the exact natural shade that matches each one.","materials":["Paper, cut into strips","Crayons or markers, assorted","Scissors, a few pairs","Masking tape, one roll"],"materialTags":["Paper","Crayons","Markers","Scissors","Masking tape"],"steps":["Before camp, or as step one, have each camper color a strip with six different squares using whatever colors they like.","Explain that the goal is to find something in nature that matches each square as closely as possible without picking anything that is alive or attached.","Set a slow, quiet pace and a clear boundary, then let campers wander to lay their strip beside leaves, bark, soil, and stones to compare.","When a camper finds a close match, they gently rest a tiny loose found item beside that square or tape it down.","Circle up and let campers show one match they are proudest of and one color they could not find anywhere.","Talk briefly about why some colors (like bright blue or pure black) are rare in nature here."],"notes":"Pre-cutting strips for younger kids saves a lot of fumbling; older kids can make harder palettes. Kids stall when they try to find perfect matches, so coach 'closest you can' early.","safety":"Set firm boundaries for wandering and remind campers to take only loose fallen items, never break leaves or disturb living plants or animals.","ages":["g13","g46","g79"],"rating":0,"media":[{"title":"Nature Color Scavenger Hunt","url":"https://www.youtube.com/watch?v=MrzVKprarEM"}],"links":[{"label":"How-to & more ideas","url":"https://www.wildwonder.org/teach/activities/sit-spot"}],"variations":["Hand out identical pre-made strips and make it a quiet race to fill all six.","Limit everyone to a single color family (all greens, all browns) and count how many distinct shades they find."],"subsets":[["Offer pre-colored strips to campers who freeze up choosing colors."],["Model gently laying a strip next to bark instead of picking the bark off."],[],[],[],[]]},
  {"id":"qo-bird-listening-map","title":"Bird Call Listening Census","altNames":["Birding by Ear","Bird Song Count","Listening for Birds"],"type":"Quiet","place":"Outside","ageMin":8,"ageMax":15,"durationMin":30,"groupMin":null,"groupMax":null,"energy":1,"prep":"Low","blurb":"Sit still with eyes closed and tally every different bird voice you can pick out of the canopy without ever seeing the singer.","materials":["Paper, one sheet per camper","Crayons or markers, assorted","Clipboards or cardboard backers (optional)"],"materialTags":["Paper","Crayons","Cardboard"],"steps":["Lead the group to a spot near trees or shrubs and have each camper sit comfortably with personal space and a sheet of paper.","Explain that birds are far easier to hear than to see, and today the goal is to COUNT different bird voices, not name them.","Have everyone close their eyes or soften their gaze and stay completely silent for the first three minutes, just listening.","Each time a camper hears what they think is a NEW bird voice, they make a quick mark or doodle of that sound on their paper.","After the silent stretch, go around and let campers share their tally and imitate one call they heard.","Add up the group's most-noticed calls and point out that birds are still singing whether or not we listen."],"notes":"Counting voices instead of naming species removes the pressure to be an expert; let kids invent their own squiggle symbols for each call. The activity dies if there is chatter, so build the silent stretch up as a challenge.","safety":"If campers close their eyes, seat them on stable ground away from slopes or water so no one tips over while not looking.","ages":["g13","g46","g79"],"rating":0,"media":[{"title":"Identify Birds by Song (Wildlife Biology for Kids Club)","url":"https://www.youtube.com/watch?v=iVdhdSeTwng"}],"links":[{"label":"How-to & more ideas","url":"https://getthekidsoutside.com/sit-spot-activities/"}],"variations":["Map calls by direction (front, behind, left, right) instead of just counting them.","Whisper-compare two listening spots, one open field and one near trees, and discuss why the counts differ."],"subsets":[["Spread campers out so neighbors' breathing and rustling don't get counted as birds."],[],["Frame the silence as a personal challenge: 'can you beat your own stillness record?'"],["Show example squiggles (a long swoop, three dots) so kids aren't stuck drawing realistic birds."],[],[]]},
  {"id":"qo-leaf-vein-sketch","title":"Leaf-Vein Close Sketching","altNames":["Leaf Detail Drawing","Vein Mapping Sketch","Botanical Leaf Study"],"type":"Quiet","place":"Both","ageMin":8,"ageMax":15,"durationMin":45,"groupMin":null,"groupMax":null,"energy":1,"prep":"Low","blurb":"Slow down and draw a single fallen leaf so carefully that every branching vein and ragged edge ends up on your paper.","materials":["Paper, one sheet per camper","Crayons, assorted","Markers, fine, a few to share","Magnifiers, one per pair (optional)"],"materialTags":["Paper","Crayons","Markers"],"steps":["Have each camper collect one interesting fallen leaf, choosing for shape and clear veins rather than for being perfect.","Sit campers down and ask them to look at the leaf for one full minute before any pencil or crayon touches paper.","Guide them to first draw only the outer outline slowly, matching every bump and tear they actually see.","Next, have them add the thick center vein, then the branching side veins, working outward like a tiny river system.","Invite campers to lightly shade the real colors, including spots or holes, instead of a flat green.","Pair up and have partners find one detail in each other's drawings that proves they really looked closely."],"notes":"The one-minute look before drawing is the whole point; without it kids draw a generic cartoon leaf from memory. Magnifiers turn vein-tracing into a treasure hunt for restless artists.","safety":"Remind campers to gather only fallen leaves and to wash hands afterward, since unknown plants can irritate skin.","ages":["g13","g46","g79"],"rating":0,"media":[{"title":"How to Draw Leaves by Observation (Art for Kids)","url":"https://www.youtube.com/watch?v=f-5edcwLJAc"}],"links":[{"label":"How-to & more ideas","url":"https://www.wildwonder.org/teach/activities/sit-spot"}],"variations":["Trade leaves with a partner halfway and try to finish their drawing from the same real leaf.","Make it a feel-only round where blindfolded campers draw a leaf using just touch, then compare to the real thing."],"subsets":[["Steer kids toward sturdy, dry leaves so they don't crumble mid-drawing."],["Tell wiggly kids the look-first minute is part of the skill, not a wait."],[],["Show how veins split smaller and smaller so they don't draw just one or two big lines."],[],[]]},
  {"id":"qo-five-senses-pause","title":"Five-Senses Outdoor Pause","altNames":["Sensory Grounding Sit","5-4-3-2-1 Nature Pause","Senses Check-In"],"type":"Quiet","place":"Outside","ageMin":6,"ageMax":14,"durationMin":15,"groupMin":null,"groupMax":null,"energy":1,"prep":"None","blurb":"A short guided sit where campers find five things they can see, four they hear, three they feel, two they smell, and one they taste in the air.","materials":["No materials needed"],"materialTags":["No materials"],"steps":["Spread the group out so each camper has a quiet patch of ground and ask everyone to settle and take three slow breaths.","Guide them to silently notice FIVE things they can see right now, looking for small details, not big obvious ones.","Move to FOUR things they can hear, then THREE things they can feel touching their skin or hands.","Shift to TWO smells in the air, then ONE taste they can notice, even if it is just the warm air.","Sit in full silence together for thirty seconds before slowly opening up and stretching.","Go around the circle and let each camper share just one thing from any sense that surprised them."],"notes":"This is the perfect reset between two high-energy blocks; keep your guiding voice low and unhurried. Younger kids may need you to count the senses out loud with them so they don't lose track.","safety":"Choose shaded, comfortable ground and let any camper who dislikes sitting still simply observe quietly while standing.","ages":["g13","g46","g79"],"rating":0,"media":[{"title":"5-4-3-2-1 Grounding Mindful Activity for Kids","url":"https://www.youtube.com/watch?v=kFF2mVjZeLw"}],"links":[{"label":"How-to & more ideas","url":"https://getthekidsoutside.com/sit-spot-activities/"}],"variations":["Run it as a transition tool with no sharing, just the silent countdown, to calm a wound-up group.","Have campers write or draw their five sights afterward to build a sensory journal page."],"subsets":[["Set campers far enough apart that they aren't tempted to whisper to a neighbor."],["For young kids, say each 'see' item count aloud so nobody loses their place."],[],[],[],[]]},
  {"id":"qo-micro-hike","title":"Inch-by-Inch Micro Hike","altNames":["String Trail Safari","One-Meter Wilderness","Tiny World Walk"],"type":"Quiet","place":"Outside","ageMin":7,"ageMax":13,"durationMin":30,"groupMin":null,"groupMax":null,"energy":1,"prep":"Low","blurb":"Crawl along a short string laid through the grass as if it were a miles-long trail, narrating every tiny landmark you pass.","materials":["Yarn or string, cut into one-meter lengths","Magnifiers, one per camper (optional)","Paper, one sheet per camper","Crayons, assorted"],"materialTags":["Yarn","Paper","Crayons"],"steps":["Give each camper a one-meter length of yarn and have them lay it as a winding 'trail' through grass, leaves, or soil.","Explain that they will travel this trail on hands and knees, eyes close to the ground, as if it were a huge wilderness.","Have campers move slowly along the string, pausing to study every tiny landmark: a stone 'mountain', a leaf 'forest', a bug 'traveler'.","Ask each camper to choose and draw their favorite three landmarks as a tiny trail map.","Invite a few campers to give a thirty-second 'tour' of their micro hike to a partner.","Coil up the yarn and reflect on how much was hiding in one meter of ground."],"notes":"The hands-and-knees viewpoint is what makes ordinary grass feel epic, so encourage kids to really get low. If knees on the ground bother some kids, let them sit and lean in instead.","safety":"Scan each camper's chosen patch for stinging insects, thorns, or animal waste before they put hands and knees down.","ages":["g13","g46","g79"],"rating":0,"links":[{"label":"How-to & more ideas","url":"https://www.wildwonder.org/teach/activities/sit-spot"}],"variations":["Make it a quiet storytelling challenge where the micro hike becomes a tale of a beetle's journey home.","Lay all strings end to end into one long class trail and tour it as a group."],"subsets":[["Show how a curvy string reveals more than a straight one."],[],["Remind kids that 'landmarks' can be tiny: a single seed counts."],[],[],[]]},
  {"id":"qo-shadow-trace","title":"Sun and Shadow Tracing","altNames":["Shadow Drawing Study","Sundial Sit","Tracing the Light"],"type":"Quiet","place":"Outside","ageMin":6,"ageMax":12,"durationMin":30,"groupMin":null,"groupMax":null,"energy":1,"prep":"Low","blurb":"Trace the crisp shadow of a leaf or twig on the pavement, then return later to see how the moving sun has quietly redrawn it.","materials":["Sidewalk chalk, assorted","Small found objects (twigs, leaves)","Paper, one sheet per camper (optional)"],"materialTags":["Sidewalk chalk","Paper"],"steps":["Find a sunny patch of pavement and have each camper pick one small found object like a twig, leaf, or pinecone.","Have campers set their object on the ground and carefully chalk-trace the exact edge of its shadow.","Ask them to label the trace with the current time or just a small 'first' star.","Send the group off to a different quiet observation activity for fifteen to twenty minutes.","Return to the same spots and have campers trace the same shadow again in a new chalk color without moving the object.","Gather and discuss why the shadow moved and which direction it slid, connecting it to the sun's path."],"notes":"This pairs perfectly as bookends around another quiet activity so the wait feels natural. Make sure objects stay put by choosing a calm, low-traffic stretch of pavement.","safety":"Keep campers from staring directly at the sun and apply or check sunscreen since this happens on open, sunny pavement.","ages":["g13","g46"],"rating":0,"media":[{"title":"Shadow Drawing - Fun Kids Activity","url":"https://www.youtube.com/watch?v=8JxLyGhKto4"}],"links":[{"label":"How-to & more ideas","url":"https://getthekidsoutside.com/sit-spot-activities/"}],"variations":["Trace a camper's own shadow morning and afternoon to make a human sundial.","Predict before the second trace which way the shadow will have moved and check who was right."],"subsets":[["Help young kids pick objects with clear, simple shapes that cast a readable shadow."],["Show how holding the chalk low and steady gives a crisp edge."],[],["Mark each object's spot with a small chalk dot so it can be replaced exactly."],[],[]]},
  {"id":"qo-seed-pod-sort","title":"Seed and Pod Sorting Study","altNames":["Seed Detective Sort","Pod and Pip Inspection","Nature Sorting Tray"],"type":"Quiet","place":"Both","ageMin":7,"ageMax":13,"durationMin":30,"groupMin":null,"groupMax":null,"energy":1,"prep":"Low","blurb":"Gather a handful of fallen seeds and pods, then quietly sort and inspect them to figure out how each one is built to travel.","materials":["Paper plates, two or three per camper","Paper, one sheet per camper","Crayons or markers, assorted","Magnifiers, one per pair (optional)"],"materialTags":["Paper plates","Paper","Crayons","Markers"],"steps":["Give campers a few minutes to collect a small handful of fallen seeds, pods, or winged samaras from a bounded area.","Have each camper spread their collection on a paper plate and look closely at the shapes without naming anything yet.","Ask them to sort their seeds into groups by a rule they choose: size, shape, fuzzy versus smooth, or winged versus round.","Introduce the idea that seeds travel by wind, by sticking to fur, or by being carried, and have campers re-sort by 'how it moves'.","Invite campers to draw and label the one seed they find most clever at traveling.","Share a few designs as a group and gently return the seeds outdoors."],"notes":"The 'how does it travel' frame turns sorting into real biology and keeps older kids engaged. Bring a few backup seeds in case the season or site is bare.","safety":"Make a firm no-tasting rule, since some seeds are toxic, and have campers wash hands when finished.","ages":["g13","g46","g79"],"rating":0,"links":[{"label":"How-to & more ideas","url":"https://www.wildwonder.org/teach/activities/sit-spot"}],"variations":["Drop winged and round seeds from a standing height and compare how they fall.","Make it a quiet matching game where partners try to pair identical seeds from mixed piles."],"subsets":[["Set a clear collecting boundary so kids don't wander hunting for more."],[],["Praise any sorting rule a camper invents so they feel ownership."],["Offer the three travel categories as a hint only if a camper is stuck."],[],[]]},
  {"id":"qo-weather-sky-watch","title":"Weather Watcher's Quiet Log","altNames":["Sky and Weather Journal","Cloud and Wind Watch","Weather Observation Sit"],"type":"Quiet","place":"Outside","ageMin":8,"ageMax":15,"durationMin":30,"groupMin":null,"groupMax":null,"energy":1,"prep":"Low","blurb":"Become a quiet weather station, reading the wind, sky, temperature, and clouds and recording today's conditions like a real meteorologist.","materials":["Paper, one sheet per camper","Crayons or markers, assorted","Strips of yarn or ribbon (for wind)","Clipboards or cardboard backers (optional)"],"materialTags":["Paper","Crayons","Markers","Yarn","Cardboard"],"steps":["Hand each camper a sheet and have them divide it into four boxes: sky, wind, air, and a prediction.","Have campers tie or hold a short yarn strip and watch which way it blows to read wind direction and strength.","Ask them to look up and note the cloud cover in their own words, from 'totally clear' to 'gray blanket'.","Have them describe how the air feels on their skin, warm or cool, dry or sticky, in the 'air' box.","Using all their clues, have each camper write or draw a prediction for what the weather will do in the next hour.","Share predictions as a group and agree to check back later to see who read the sky best."],"notes":"Letting kids predict and then verify later is the hook that makes this stick; keep their language descriptive rather than technical. A breezy, partly-cloudy day gives the richest observations.","safety":"Run this only in safe weather and head indoors immediately if you hear thunder or see lightning approaching.","ages":["g13","g46","g79"],"rating":0,"media":[{"title":"Be a Weather Watcher (SciShow Kids)","url":"https://www.youtube.com/watch?v=Uo8lbeVVb4M"}],"links":[{"label":"How-to & more ideas","url":"https://getthekidsoutside.com/sit-spot-activities/"}],"variations":["Keep a multi-day camp weather log and look for patterns across the week.","Add a homemade rain-or-shine vote where campers commit to a prediction and tally the group's guesses."],"subsets":[["Pre-fold the four boxes for younger campers so setup is instant."],["Show how a limp yarn means calm and a streaming yarn means strong wind."],[],[],["Encourage kids to use their actual clues, not just guess randomly."],[]]},
  {"id":"qo-smell-scent-map","title":"Scent Trail Smell Map","altNames":["Nature Scent Hunt","Smelling Safari","Aroma Mapping Sit"],"type":"Quiet","place":"Outside","ageMin":7,"ageMax":13,"durationMin":30,"groupMin":null,"groupMax":null,"energy":1,"prep":"Low","blurb":"Move quietly through the grounds with your eyes doing less work than your nose, mapping every smell from sweet to earthy you can find.","materials":["Paper, one sheet per camper","Crayons or markers, assorted","Paper cups, one per camper (optional, for collecting scents)"],"materialTags":["Paper","Crayons","Markers","Paper cups"],"steps":["Have each camper draw a rough simple map of the immediate area with a few landmarks like a tree, a path, and a fence.","Explain that today the nose leads: they will walk slowly and quietly, sniffing the air, the ground, leaves, and bark.","When a camper notices a distinct smell, they mark that spot on their map and label it with a word or a doodle.","Encourage gentle 'scent collecting': cupping a hand near a leaf and wafting the smell toward the nose rather than crushing plants.","After mapping, have campers rate their smells from favorite to least favorite and circle the strongest one.","Circle up and let campers lead a partner to the single smelliest spot on their map."],"notes":"Wafting instead of crushing protects plants and teaches a real lab skill; demo it first. Damp or shaded areas usually carry the richest earthy smells, so route the walk through them.","safety":"Tell campers never to put unknown plants, berries, or fungi in or near their mouths and to waft scents, never deeply inhale unknown substances up close.","ages":["g13","g46","g79"],"rating":0,"media":[{"title":"Observing Nature Through Smell (Wildlife Biology for Kids Club)","url":"https://www.youtube.com/watch?v=4drgulU4kb8"}],"links":[{"label":"How-to & more ideas","url":"https://www.wildwonder.org/teach/activities/sit-spot"}],"variations":["Make it a blind-nose challenge where a partner guides a closed-eyes camper to identify spots by smell alone.","Compare the scent map of a sunny area to a shady damp one and discuss why they differ."],"subsets":[["Keep maps simple; three landmarks is plenty for orientation."],[],[],["Demonstrate the hand-wafting motion so kids don't grab and tear leaves."],[],[]]},
];
